def solve(nums: List[int]) -> int:
    n = len(nums)
    sorted_nums = sorted(nums)

    for k in range(n - 1, -1, -1):
        visited = [False] * n
        can_sort = True

        for i in range(n):
            if visited[i]:
                continue
            curr = nums[i]
            target = sorted_nums[i]
            found = False

            for j in range(n):
                if visited[j]:
                    continue
                if (curr & nums[j]) == k and nums[j] == target:
                    visited[i] = True
                    visited[j] = True
                    found = True
                    break

            if not found:
                can_sort = False
                break

        if can_sort:
            return k

    return 0
